import{_ as a,o,c as t,ag as n}from"./chunks/framework.CAXxHpAX.js";const v=JSON.parse('{"title":"辛亥革命影响：","description":"","frontmatter":{},"headers":[],"relativePath":"notes/note-18.md","filePath":"notes/note-18.md"}'),e={name:"notes/note-18.md"};function r(s,p,l,c,d,i){return o(),t("div",null,[...p[0]||(p[0]=[n('<h1 id="辛亥革命影响" tabindex="-1">辛亥革命影响： <a class="header-anchor" href="#辛亥革命影响" aria-label="Permalink to &quot;辛亥革命影响：&quot;">​</a></h1><p><span style="color:var(--vp-c-brand-1);font-weight:bold;">辛亥革命影响：</span></p><p>①推翻了清王朝的反动统治，结束了封建帝制；</p><p>②它开创了完全意义上的近代民族民主革命，极大地推动了中华民族的思想解放，</p><p>③促进民族资本主义的发展</p><p><span style="color:var(--vp-c-brand-1);font-weight:bold;">④社会观念的转变和移风易俗。局限：</span></p><p>⑤没有完成反帝反封建的任务；没有改变半殖民地半封建社会。</p><p><span style="color:var(--vp-c-brand-1);font-weight:bold;">1、中国同盟会成立：</span></p><p>1</p><p>9</p><p>0</p><p><span style="color:var(--vp-c-brand-1);font-weight:bold;">5、东京 机关报：</span>《民报》</p><p><span style="color:var(--vp-c-brand-1);font-weight:bold;">2、同盟会政治纲领：</span>驱除鞑虏、恢复中华（民族）、创立民国（民权）、平均地权（民生）</p><p><span style="color:var(--vp-c-brand-1);font-weight:bold;">3、地位：</span>第一个全国规模的、统一的资产阶级革命政党。</p><p>4、1911年广州黄花岗起义，革命党人不屈不挠的精神和视死如归的英雄气概鼓舞了全国人民的斗志。</p><p><span style="color:var(--vp-c-brand-1);font-weight:bold;">5、辛亥革命：</span>1911年10月10日、武昌</p><p><span style="color:var(--vp-c-brand-1);font-weight:bold;">6、宣传革命思想的著作：</span>《革命军》《猛回头》《警示钟》《驳康有为论革命书》</p><p><span style="color:var(--vp-c-brand-1);font-weight:bold;">7、辛亥革命的背景：</span>《辛丑条约》后，清政府沦为帝国主义统治中国的工具，国内革命情绪高涨。</p><p><span style="color:var(--vp-c-brand-1);font-weight:bold;">8、辛亥革命的成果：</span>民国、清帝退位、《中国民国临时约法》</p><p><span style="color:var(--vp-c-brand-1);font-weight:bold;">9、《中国民国临时约法》性质和影响：</span>中国历史上第一部具有资产阶级共和国宪法性质的重要文件；肯定资产阶级民主共和制度和民主自由的原则、</p><p>1</p><p>0、宋教仁案—二次革命—袁复辟帝制—护国运动—北洋军阀混战</p>',22)])])}const _=a(e,[["render",r]]);export{v as __pageData,_ as default};
